  # Build clause fragments for each subject without trailing periods
      clauses: list[str] = []
      for subj, phrases in subject_phrases.items():
          if len(phrases) == 1:
              clauses.append(f"{subj} {phrases[0]}")
          else:
              clauses.append(f"{subj} " + ", ".join(phrases[:-1]) + ", and " + phrases[-1])

      # Combine all clauses into a single complex sentence
      if not clauses:
          result = ""
      elif len(clauses) == 1:
          result = clauses[0] + "."
      else:
          # Use semicolons to separate different subject clauses, with a final conjunction
          result = "; ".join(clauses[:-1]) + ", and " + clauses[-1] + "."

      # Capitalize the first character of the final output
      result = result[:1].upper() + result[1:] if result else ""
      return result
